import React, { useState } from "react";
import "./IncomeTypes.css";
import logo from "../../icons/logo.png";
import { useNavigate } from "react-router-dom";

const OPTIONS = [
  { id: "project", label: "Додати розподіл доходів з проекту" },
  { id: "clients", label: "Додати розподіл доходів з перших клієнтів компанії" },
  { id: "profit", label: "Додати розподіл доходів з чистого прибутку компанії" },
];

export const IncomeTypes: React.FC = () => {
  const navigate = useNavigate();
  const [selected, setSelected] = useState<string[]>([]);

  const toggle = (id: string) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id]
    );
  };

  return (
    <div className="income-types-wrapper">
      <div className="income-types-card">
        <img className="income-types-logo" src={logo} alt="logo" />

        <h2 className="income-types-title">
          Розподіл інших видів майбутнього доходу
        </h2>

        <div className="income-options">
          {OPTIONS.map((opt) => (
            <button
              key={opt.id}
              className={`income-option-btn${selected.includes(opt.id) ? " selected" : ""}`}
              onClick={() => toggle(opt.id)}
            >
              {opt.label}
            </button>
          ))}
        </div>

        <div className="income-types-footer">
          <button
            className="income-continue-btn"
            onClick={() => navigate("/summary")}
          >
            Продовжити
          </button>
        </div>
      </div>
    </div>
  );
};
